mapper.select:
SELECT
    lr.id,
    lr.student_id,
    lr.course_id,
    lr.chapter_id,
    lr.video_id,
    lr.start_time,
    lr.end_time,
    lr.duration,
    lr.video_progress,
    lr.last_position,
    lr.created_time
FROM learning_record lr


        AND lr.student_id = #{q.studentId}


        AND lr.course_id = #{q.courseId}


        AND lr.chapter_id = #{q.chapterId}


        AND lr.video_id = #{q.videoId}


        AND lr.created_time >= #{q.startTime}


        AND lr.created_time <= #{q.endTime}


ORDER BY lr.created_time DESC

SELECT lr.id, lr.student_id, lr.course_id, lr.chapter_id, lr.video_id, lr.start_time, lr.end_time, lr.duration, lr.video_progress, lr.last_position, lr.created_time FROM learning_record lr INNER JOIN ( SELECT student_id, video_id, MAX(id) AS max_id FROM learning_record WHERE course_id = #{courseId}
AND student_id = #{studentId}
AND chapter_id = #{chapterId}
GROUP BY student_id, video_id ) latest ON lr.id = latest.max_id ORDER BY lr.student_id ASC, lr.chapter_id ASC, lr.video_id ASC

SELECT
    student_id AS studentId,
    COALESCE(SUM(duration), 0) AS totalStudyTime,
    MAX(end_time) AS lastStudyTime
FROM learning_record
WHERE course_id = #{courseId}

    AND student_id = #{studentId}


    AND chapter_id = #{chapterId}

GROUP BY student_id

SELECT
    chapter_id AS chapterId,
    COALESCE(SUM(duration), 0) AS totalStudyTime
FROM learning_record
WHERE course_id = #{courseId}

    AND student_id = #{studentId}


    AND chapter_id = #{chapterId}

GROUP BY chapter_id
